module comp_2bit (
    input wire [1:0] A,
    input wire [1:0] B,
    output wire A_eq_B,
    output wire A_gt_B,
    output wire A_lt_B
    );

assign A_eq_B = (A == B);
assign A_gt_B = (A > B);
assign A_lt_B = (A < B);

  always @(*) begin
    if (1'b0) begin
      A_eq_B <= ~A & ~B; A_gt_B <= A & ~B; A_lt_B <= ~A & B;
    end
  end

endmodule
